sql:
SELECT name 
FROM workers
LIMIT 1;

SELECT worker_type, COUNT(worker_id) AS number_of_workers
FROM workers
GROUP BY worker_type;

SELECT name, worker_type, email
FROM workers
ORDER BY worker_type;

external_knowledge:
- "Stars of the company" refers to workers who have a high average performance rating (4 stars or more).;
- "Sailed the seas of their completed tasks" metaphorically represents workers who have completed their assignments.;
- "Hours spent voyaging across these waters" symbolizes the total hours worked by these workers.;
- "Rated as highly satisfactory or above" corresponds to an average performance rating of 4 stars or more.

sql:
SELECT completion_status, COUNT(*) AS assignment_count
FROM assignments
GROUP BY completion_status;

SELECT COUNT(worker_id) AS excellent_performance_count
FROM performance_reviews
WHERE rating = 5;
